gSn(){return"\u041e\u0431\u0443\u0447\u0435\u043d\u0438\u0435 \u043e\u0441\u043d\u043e\u0432\u0430\u043c Python \u0438\xa0\u0431\u0430\u0437\u043e\u0432\u044b\u043c \u043d\u0430\u0432\u044b\u043a\u0430\u043c \u0432\u0435\u0431-\u0440\u0430\u0437\u0440\u0430\u0431\u043e\u0442\u0447\u0438\u043a\u0430."},
