gQS(){return"2022 \u2014 2024"},
gQV(){return"\u0420\u0430\u0437\u0440\u0430\u0431\u043e\u0442\u043a\u0430 backend\xa0\u0441\u0435\u0440\u0432\u0438\u0441\u043e\u0432, \u0432\u043d\u0435\u0434\u0440\u0435\u043d\u0438\u0435 DevOps, \u043f\u0435\u0440\u0435\u0440\u0430\u0431\u043e\u0442\u043a\u0430 \u0430\u0440\u0445\u0438\u0442\u0435\u043a\u0442\u0443\u0440\u044b."},
gQT(){return"\u0420\u0430\u0437\u0440\u0430\u0431\u043e\u0442\u043a\u0430 backend\xa0\u0441\u0435\u0440\u0432\u0438\u0441\u043e\u0432 \u0434\u043b\u044f \u0432\u044b\u0441\u043e\u043a\u043e\u0439 \u043d\u0430\u0433\u0440\u0443\u0437\u043a\u0438.\n\u041f\u0435\u0440\u0435\u0440\u0430\u0431\u043e\u0442\u043a\u0430 \u0430\u0440\u0445\u0438\u0442\u0435\u043a\u0442\u0443\u0440\u044b backend\xa0\u0441\u0435\u0440\u0432\u0438\u0441\u043e\u0432.\n\u0421\u043c\u0435\u043d\u0430 \u0444\u0440\u0435\u0439\u043c\u0432\u043e\u0440\u043a\u043e\u0432 backend\xa0\u0441\u0435\u0440\u0432\u0438\u0441\u043e\u0432.\n\u0420\u0430\u0437\u0440\u0430\u0431\u043e\u0442\u043a\u0430 CI/CD \u0434\u043b\u044f \u0431\u043e\u043b\u044c\u0448\u043e\u0433\u043e \u043c\u043e\u043d\u043e\u043b\u0438\u0442\u0430.\n\u041f\u043e\u0434\u0434\u0435\u0440\u0436\u043a\u0430 API \u043b\u0438\u0447\u043d\u043e\u0433\u043e \u043a\u0430\u0431\u0438\u043d\u0435\u0442\u0430.\n\u0414\u0440\u043e\u0431\u043b\u0435\u043d\u0438\u0435 \u043c\u043e\u043d\u043e\u043b\u0438\u0442\u0430 \u043d\u0430\xa0\u043c\u0438\u043a\u0440\u043e\u0441\u0435\u0440\u0432\u0438\u0441\u044b.\n\u0420\u0435\u0444\u0430\u043a\u0442\u043e\u0440\u0438\u043d\u0433 \u043a\u043e\u0434\u043e\u0432\u043e\u0439 \u0431\u0430\u0437\u044b.\n\u0418\u043d\u0442\u0435\u0433\u0440\u0430\u0446\u0438\u044f \u0441\xa0CRM-\u0441\u0438\u0441\u0442\u0435\u043c\u0430\u043c\u0438 (Tessa, Elma, Arena).\n\u041b\u0443\u0447\u0448\u0438\u0439 \u0443\u0447\u0430\u0441\u0442\u043d\u0438\u043a \u043f\u0440\u043e\u0435\u043a\u0442\u043d\u043e\u0439 \u043a\u043e\u043c\u0430\u043d\u0434\u044b DevOps.\n\u041f\u0440\u043e\u0432\u0435\u0434\u0435\u043d\u0438\u0435 \u043b\u043e\u043a\u0430\u043b\u044c\u043d\u044b\u0445 \u043c\u0438\u0442\u0430\u043f\u043e\u0432 \u0434\u043b\u044f \u0440\u0430\u0437\u0440\u0430\u0431\u043e\u0442\u0447\u0438\u043a\u043e\u0432.\n\u041f\u0440\u043e\u0432\u0435\u0434\u0435\u043d\u0438\u0435 \u0442\u0435\u0445\u043d\u0438\u0447\u0435\u0441\u043a\u0438\u0445 \u0441\u043e\u0431\u0435\u0441\u0435\u0434\u043e\u0432\u0430\u043d\u0438\u0439."},
